package org.apache.commons.math.dfp;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.dfp.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.dfp.steps;

import org.apache.commons.math.dfp.Dfp;
import org.apache.commons.math.dfp.DfpField;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

public class StepDefs {

    private DfpField field;
    private Dfp dfpValue;
    private double result;

    @Given("a Dfp field with 100 digits")
    public void a_Dfp_field_with_100_digits() {
        field = new DfpField(100);
    }

    @When("I create a Dfp instance from value {double}")
    public void i_create_a_Dfp_instance_from_value(double value) {
        dfpValue = field.newDfp(value);
    }

    @When("I get the default zero value from the field")
    public void i_get_the_default_zero_value_from_the_field() {
        dfpValue = field.getZero();
    }

    @Then("the toDouble conversion should return {double}")
    public void the_toDouble_conversion_should_return(double expected) {
        result = dfpValue.toDouble();
        assertEquals(expected, result, 0.0);
    }

    @Then("the result should be positive zero")
    public void the_result_should_be_positive_zero() {
        assertTrue("Result is not positive zero", 
                   Double.doubleToRawLongBits(result) == Double.doubleToRawLongBits(0.0));
    }

    @Then("the result should be negative zero")
    public void the_result_should_be_negative_zero() {
        assertTrue("Result is not negative zero", 
                   Double.doubleToRawLongBits(result) == Double.doubleToRawLongBits(-0.0));
    }
}
